function reportSlice(s){const nights=[...s.nights].sort((a,b)=>b.date.localeCompare(a.date));if(!reportNightId||!s.nights.some(n=>n.id===reportNightId))reportNightId=nights[0]?.id||"";return reportMode==="season"?s:{...s,nights:s.nights.filter(n=>n.id===reportNightId)}}
